class Solution:
    def canReorderDoubled(self, arr):
        from collections import Counter
        cnt = Counter(arr)
        for x in sorted(cnt, key=abs):
            if cnt[x] == 0:
                continue
            if x == 0:
                if cnt[x] % 2 != 0:
                    return False
                cnt[x] = 0
                continue
            need = 2 * x
            if cnt[need] < cnt[x]:
                return False
            cnt[need] -= cnt[x]
            cnt[x] = 0
        return True

