var canReorderDoubled = function(arr) {
    const cnt = new Map();
    for (const v of arr) cnt.set(v, (cnt.get(v) || 0) + 1);
    const order = [...arr].sort((a, b) => Math.abs(a) - Math.abs(b));
    for (const x of order) {
        if ((cnt.get(x) || 0) === 0) continue;
        if ((cnt.get(2 * x) || 0) <= 0) return false;
        cnt.set(x, cnt.get(x) - 1);
        cnt.set(2 * x, cnt.get(2 * x) - 1);
    }
    return true;
};
